<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Conway's Game of Life</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }

  body {
    background: #0a0a0f;
    color: #e0e0e0;
    font-family: 'Segoe UI', system-ui, -apple-system, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    overflow: hidden;
    user-select: none;
  }

  h1 {
    font-size: 1.6rem;
    margin-bottom: 12px;
    background: linear-gradient(90deg, #ff6fd8, #3813c2);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    letter-spacing: 2px;
    text-transform: uppercase;
  }

  #life {
    border: 2px solid #2a2a3a;
    border-radius: 8px;
    cursor: crosshair;
    display: block;
    box-shadow: 0 0 40px rgba(56, 19, 194, 0.15), 0 0 80px rgba(255, 111, 216, 0.07);
    image-rendering: pixelated;
  }

  .controls {
    display: flex;
    gap: 10px;
    margin-top: 14px;
    flex-wrap: wrap;
    justify-content: center;
  }

  button {
    background: #1a1a2e;
    color: #c8c8ff;
    border: 1.5px solid #3a3a5c;
    padding: 10px 22px;
    font-size: 0.95rem;
    font-weight: 600;
    border-radius: 6px;
    cursor: pointer;
    transition: all 0.15s ease;
    letter-spacing: 0.5px;
  }

  button:hover {
    background: #2a2a4e;
    border-color: #6a6aff;
    color: #fff;
    box-shadow: 0 0 12px rgba(106, 106, 255, 0.3);
  }

  button:active {
    transform: scale(0.96);
  }

  button.active {
    background: #3813c2;
    border-color: #ff6fd8;
    color: #fff;
    box-shadow: 0 0 16px rgba(255, 111, 216, 0.4);
  }

  .info {
    margin-top: 10px;
    font-size: 0.8rem;
    color: #5a5a7a;
    text-align: center;
  }

  #gen-counter {
    color: #ff6fd8;
    font-weight: bold;
  }
</style>
</head>
<body>

<h1>Game of Life</h1>
<canvas id="life"></canvas>
<div class="controls">
  <button id="step">⏭ Step</button>
  <button id="play">▶ Play</button>
  <button id="random">🎲 Random</button>
  <button id="clear">💀 Clear</button>
</div>
<div class="info">Generation: <span id="gen-counter">0</span> &nbsp;|&nbsp; Click or drag on the grid to paint cells</div>

<script>
(function() {
  // --- Configuration ---
  const CELL_SIZE = 12;
  const COLS = 50;   // >= 40
  const ROWS = 50;   // >= 40
  const CANVAS_W = COLS * CELL_SIZE;  // 600px
  const CANVAS_H = ROWS * CELL_SIZE;  // 600px

  // --- Canvas setup ---
  const canvas = document.getElementById('life');
  const ctx = canvas.getContext('2d');
  canvas.width = CANVAS_W;
  canvas.height = CANVAS_H;

  // --- Grid state (two buffers for simultaneous update) ---
  let gridA = createGrid();
  let gridB = createGrid();
  let current = gridA;
  let next = gridB;
  let generation = 0;

  function createGrid() {
    const g = new Array(ROWS);
    for (let y = 0; y < ROWS; y++) {
      g[y] = new Uint8Array(COLS);
    }
    return g;
  }

  // --- API ---
  window.life = {
    get w() { return COLS; },
    get h() { return ROWS; },

    get(x, y) {
      if (x < 0 || x >= COLS || y < 0 || y >= ROWS) return 0;
      return current[y][x];
    },

    set(x, y, v) {
      if (x < 0 || x >= COLS || y < 0 || y >= ROWS) return;
      current[y][x] = v ? 1 : 0;
    },

    step() {
      // Simultaneous update: compute next from current
      for (let y = 0; y < ROWS; y++) {
        for (let x = 0; x < COLS; x++) {
          let neighbors = 0;
          for (let dy = -1; dy <= 1; dy++) {
            for (let dx = -1; dx <= 1; dx++) {
              if (dx === 0 && dy === 0) continue;
              const nx = x + dx, ny = y + dy;
              if (nx >= 0 && nx < COLS && ny >= 0 && ny < ROWS) {
                neighbors += current[ny][nx];
              }
            }
          }
          const alive = current[y][x];
          next[y][x] = (alive && (neighbors === 2 || neighbors === 3))
                        || (!alive && neighbors === 3) ? 1 : 0;
        }
      }
      // Swap buffers
      let tmp = current;
      current = next;
      next = tmp;
      generation++;
      draw();
    },

    clear() {
      for (let y = 0; y < ROWS; y++) {
        current[y].fill(0);
      }
      generation = 0;
      document.getElementById('gen-counter').textContent = '0';
      draw();
    }
  };

  // --- Drawing ---
  function draw() {
    ctx.fillStyle = '#0a0a0f';
    ctx.fillRect(0, 0, CANVAS_W, CANVAS_H);

    // Draw grid lines (subtle)
    ctx.strokeStyle = '#14142a';
    ctx.lineWidth = 0.5;
    for (let x = 0; x <= COLS; x++) {
      ctx.beginPath();
      ctx.moveTo(x * CELL_SIZE, 0);
      ctx.lineTo(x * CELL_SIZE, CANVAS_H);
      ctx.stroke();
    }
    for (let y = 0; y <= ROWS; y++) {
      ctx.beginPath();
      ctx.moveTo(0, y * CELL_SIZE);
      ctx.lineTo(CANVAS_W, y * CELL_SIZE);
      ctx.stroke();
    }

    // Draw alive cells with a nice glow effect
    for (let y = 0; y < ROWS; y++) {
      for (let x = 0; x < COLS; x++) {
        if (current[y][x]) {
          const px = x * CELL_SIZE;
          const py = y * CELL_SIZE;

          // Glow
          ctx.fillStyle = 'rgba(255, 111, 216, 0.15)';
          ctx.fillRect(px - 1, py - 1, CELL_SIZE + 2, CELL_SIZE + 2);

          // Cell body
          const grad = ctx.createRadialGradient(
            px + CELL_SIZE / 2, py + CELL_SIZE / 2, 0,
            px + CELL_SIZE / 2, py + CELL_SIZE / 2, CELL_SIZE * 0.7
          );
          grad.addColorStop(0, '#ff8ef0');
          grad.addColorStop(1, '#3813c2');
          ctx.fillStyle = grad;
          ctx.fillRect(px + 1, py + 1, CELL_SIZE - 2, CELL_SIZE - 2);

          // Highlight
          ctx.fillStyle = 'rgba(255, 255, 255, 0.2)';
          ctx.fillRect(px + 2, py + 2, CELL_SIZE * 0.3, CELL_SIZE * 0.3);
        }
      }
    }

    document.getElementById('gen-counter').textContent = generation;
  }

  // --- Mouse / Touch interaction ---
  let painting = false;
  let paintValue = 1; // what to set when painting

  function getCellFromEvent(e) {
    const rect = canvas.getBoundingClientRect();
    const scaleX = CANVAS_W / rect.width;
    const scaleY = CANVAS_H / rect.height;
    const mx = (e.clientX - rect.left) * scaleX;
    const my = (e.clientY - rect.top) * scaleY;
    const cx = Math.floor(mx / CELL_SIZE);
    const cy = Math.floor(my / CELL_SIZE);
    if (cx >= 0 && cx < COLS && cy >= 0 && cy < ROWS) {
      return { x: cx, y: cy };
    }
    return null;
  }

  canvas.addEventListener('mousedown', function(e) {
    e.preventDefault();
    painting = true;
    const cell = getCellFromEvent(e);
    if (cell) {
      paintValue = current[cell.y][cell.x] ? 0 : 1;
      window.life.set(cell.x, cell.y, paintValue);
      draw();
    }
  });

  canvas.addEventListener('mousemove', function(e) {
    if (!painting) return;
    const cell = getCellFromEvent(e);
    if (cell) {
      window.life.set(cell.x, cell.y, paintValue);
      draw();
    }
  });

  window.addEventListener('mouseup', function() {
    painting = false;
  });

  // Touch support
  canvas.addEventListener('touchstart', function(e) {
    e.preventDefault();
    const touch = e.touches[0];
    const cell = getCellFromEvent(touch);
    if (cell) {
      painting = true;
      paintValue = current[cell.y][cell.x] ? 0 : 1;
      window.life.set(cell.x, cell.y, paintValue);
      draw();
    }
  }, { passive: false });

  canvas.addEventListener('touchmove', function(e) {
    e.preventDefault();
    if (!painting) return;
    const touch = e.touches[0];
    const cell = getCellFromEvent(touch);
    if (cell) {
      window.life.set(cell.x, cell.y, paintValue);
      draw();
    }
  }, { passive: false });

  canvas.addEventListener('touchend', function() {
    painting = false;
  });

  // --- Controls ---
  let playing = false;
  let playInterval = null;
  const PLAY_SPEED = 80; // ms per generation

  document.getElementById('step').addEventListener('click', function() {
    window.life.step();
  });

  document.getElementById('play').addEventListener('click', function() {
    playing = !playing;
    const btn = document.getElementById('play');
    if (playing) {
      btn.textContent = '⏸ Pause';
      btn.classList.add('active');
      playInterval = setInterval(function() {
        window.life.step();
      }, PLAY_SPEED);
    } else {
      btn.textContent = '▶ Play';
      btn.classList.remove('active');
      clearInterval(playInterval);
      playInterval = null;
    }
  });

  document.getElementById('random').addEventListener('click', function() {
    for (let y = 0; y < ROWS; y++) {
      for (let x = 0; x < COLS; x++) {
        current[y][x] = Math.random() < 0.3 ? 1 : 0;
      }
    }
    generation = 0;
    document.getElementById('gen-counter').textContent = '0';
    draw();
  });

  document.getElementById('clear').addEventListener('click', function() {
    window.life.clear();
  });

  // --- Initial draw ---
  draw();
})();
</script>
</body>
</html>
```
